public class ThreadLifecycleDemo {
    public static void main(String[] args) {
        // New state
        Thread t = new Thread(new MyRunnable());
        System.out.println("State after creation: " + t.getState());

        // Runnable state
        t.start();
        System.out.println("State after start: " + t.getState());

        // Showing different states
        try {
            // Thread in running state
            System.out.println("Main thread running");

            // Wait for thread to finish
            t.join();  // Waiting state for main
            System.out.println("Thread finished, state: " + t.getState());
        } catch (InterruptedException e) {
            e.printStackTrace();
        }

        // Thread terminated
        System.out.println("Final state: " + t.getState());
    }
}

class MyRunnable implements Runnable {
    @Override
    public void run() {
        try {
            System.out.println("Thread running, state: " + Thread.currentThread().getState());
            Thread.sleep(1000);  // Timed waiting
            System.out.println("Thread woke up");
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
    }
}

