}

public class IsAliveJoinDemo {
    public static void main(String[] args) throws InterruptedException {
        // isAlive() demonstration
        System.out.println("=== isAlive() Demonstration ===");
        Thread t1 = new Thread(new Worker(), "Worker-1");

        System.out.println("Before start: " + t1.isAlive());
        t1.start();
        System.out.println("After start: " + t1.isAlive());

        Thread.sleep(100);
        System.out.println("During execution: " + t1.isAlive());

        t1.join();
        System.out.println("After join: " + t1.isAlive());

        // join() demonstration
        System.out.println("\n=== join() Demonstration ===");
        Thread t2 = new Thread(new Worker(), "Worker-2");
        Thread t3 = new Thread(new Worker(), "Worker-3");

        t2.start();
        t3.start();

        System.out.println("Waiting for threads to finish...");
        t2.join();  // Wait for t2
        t3.join();  // Wait for t3
        System.out.println("All threads completed!");

        // Multiple join with timeout
        System.out.println("\n=== join() with Timeout ===");
        Thread t4 = new Thread(new LongWorker(), "Worker-4");
        t4.start();

        // Wait for 2 seconds max
        t4.join(2000);
        System.out.println("Main thread continued after 2 seconds");

        if (t4.isAlive()) {
            System.out.println("Worker-4 is still running");
            t4.interrupt();
        } else {
            System.out.println("Worker-4 completed");
        }
    }
}

