public class PriorityDemo {
    public static void main(String[] args) {
        System.out.println("=== Thread Priority Demonstration ===\n");

        // Create threads with different priorities
        PriorityThread low = new PriorityThread("Low");
        PriorityThread normal = new PriorityThread("Normal");
        PriorityThread high = new PriorityThread("High");

        // Set priorities
        low.setPriority(Thread.MIN_PRIORITY);
        normal.setPriority(Thread.NORM_PRIORITY);
        high.setPriority(Thread.MAX_PRIORITY);

        System.out.println("Low priority: " + low.getPriority());
        System.out.println("Normal priority: " + normal.getPriority());
        System.out.println("High priority: " + high.getPriority());

        // Start threads
        low.start();
        normal.start();
        high.start();

        // Wait for threads
        try {
            low.join();
            normal.join();
            high.join();
        } catch (InterruptedException e) {
            e.printStackTrace();
        }

        System.out.println("\nAll threads completed");
        System.out.println("Count - Low: " + PriorityThread.lowCount);
        System.out.println("Count - Normal: " + PriorityThread.normalCount);
        System.out.println("Count - High: " + PriorityThread.highCount);
    }
}

class PriorityThread extends Thread {
    static int lowCount = 0;
    static int normalCount = 0;
    static int highCount = 0;

    PriorityThread(String name) {
        super(name);
    }

    @Override
    public void run() {
        for (int i = 0; i < 1000000; i++) {
            // Increment appropriate counter
            if (getPriority() == Thread.MIN_PRIORITY) {
                lowCount++;
            } else if (getPriority() == Thread.MAX_PRIORITY) {
                highCount++;
            } else {
                normalCount++;
            }
        }
        System.out.println(getName() + " priority thread completed");
    }
}

class TicketCounter {
    private int availableSeats = 10;

    // Synchronized method
    public synchronized boolean bookTicket(String threadName, int seats) {
        System.out.println(threadName + " attempting to book " + seats + " seats");

        if (seats <= availableSeats) {
            availableSeats -= seats;
            System.out.println(threadName + " booked " + seats + " seats. Remaining: " + availableSeats);
            return true;
        } else {
            System.out.println(threadName + " failed. Only " + availableSeats + " seats available");
            return false;
        }
    }

    // Synchronized block example
    public void processBooking(String threadName, int seats) {
        // Other code
        synchronized(this) {
            if (seats <= availableSeats) {
                availableSeats -= seats;
                System.out.println(threadName + " (block) booked " + seats + " seats. Remaining: " + availableSeats);
            }
        }
    }
}

