public class SynchronizationDemo {
    public static void main(String[] args) throws InterruptedException {
        System.out.println("=== Ticket Booking System (Synchronized) ===\n");

        TicketCounter counter = new TicketCounter();

        // Create multiple threads booking tickets
        Thread t1 = new BookingThread("Thread-1", counter, 3);
        Thread t2 = new BookingThread("Thread-2", counter, 2);
        Thread t3 = new BookingThread("Thread-3", counter, 4);
        Thread t4 = new BookingThread("Thread-4", counter, 5);

        t1.start();
        t2.start();
        t3.start();
        t4.start();

        t1.join();
        t2.join();
        t3.join();
        t4.join();

        // Demonstrate without synchronization
        System.out.println("\n=== Without Synchronization ===");
        UnsafeCounter unsafe = new UnsafeCounter();
        Thread[] threads = new Thread[10];

        for (int i = 0; i < 10; i++) {
            threads[i] = new Thread(() -> {
                for (int j = 0; j < 1000; j++) {
                    unsafe.increment();
                }
            });
            threads[i].start();
        }

        for (Thread t : threads) {
            t.join();
        }

        System.out.println("Unsafe counter (should be 10000): " + unsafe.getCount());

        // With synchronization
        System.out.println("\n=== With Synchronization ===");
        SafeCounter safe = new SafeCounter();
        Thread[] safeThreads = new Thread[10];

        for (int i = 0; i < 10; i++) {
            safeThreads[i] = new Thread(() -> {
                for (int j = 0; j < 1000; j++) {
                    safe.increment();
                }
            });
            safeThreads[i].start();
        }

        for (Thread t : safeThreads) {
            t.join();
        }

        System.out.println("Safe counter (should be 10000): " + safe.getCount());
    }
}

class UnsafeCounter {
    private int count = 0;

    void increment() {
        count++;
    }

    int getCount() {
        return count;
    }
}

class SafeCounter {
    private int count = 0;

    synchronized void increment() {
        count++;
    }

    int getCount() {
        return count;
    }
}

